  let t = $('Webhook').item.json.body.sender;

  // remove o sufixo do WhatsApp
  t = t.replace('@s.whatsapp.net', '');

  if (t.length === 8) {
    t = "11" + "9" + t;
  } else if (t.length === 9) {
    t = "11" + t;
  } else if (t.length === 10) {
    t = t.replace(/^(\d{2})(\d{8})$/, "$19$2");
  } else if (t.length === 11) {
    t = "55" + t;
  } else if (t.length === 12) {
    t = t.slice(0, 4) + "9" + t.slice(4);
  } else if (t.length > 13) {
    t = t.slice(-13);
  }

  return t;
})()
}}

